import React from "react";
import Navbar from "./layout/Navbar";
import Footer from "./layout/Footer";
import Hero from "./sections/Hero";
import Contact from "./sections/Contact";
import About from "./sections/About";
import Projects from "./sections/Projects";
import Experience from "./sections/Experience";
import { motion } from "framer-motion";
import ocean from "./assets/ocean.jpg";

const App = () => {
  return (
    <div className="relative min-h-screen overflow-x-hidden text-main">
      {/* Background */}
      <motion.img
        src={ocean}
        className="fixed top-0 left-0 w-full h-full object-cover -z-10"
        initial={{ scale: 1.05 }}
        animate={{ scale: 1 }}
        transition={{ duration: 3, ease: "easeOut" }}
      />

      {/* Overlay */}
      {/* <div className="absolute inset-0 bg-linear-to-b from-black/85 via-black/80 to-black/85"></div> */}
      <div className="absolute inset-0 bg-black/85"></div>
      {/* Content */}
      <div className=" relative z-20">
        <Navbar />
        <main>
          <Hero />
          <About />
          <Projects />
          <Experience />
          <Contact />
        </main>
        <Footer />
      </div>
    </div>
  );
};

export default App;

import React from "react";
import { motion } from "framer-motion";

const Button = ({
  children,
  size = "default",
  variant = "primary",
  className = "",
  ...props
}) => {
  /* 🔹 Base styles */
  const baseClass =
    "items-center justify-center gap-2 rounded-full font-medium  hover:bg-header/95 shadow-lg shadow-header/25  focus-visible:ring-2 focus-visible:ring-header/50 ";

  /* 🔹 Sizes */
  const sizeClasses = {
    sm: "px-4 py-2 text-sm",
    default: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-lg",
  };

  /* 🔹 Variants */
  const variantClasses = {
    primary:
      "text-white bg-header/90 hover:bg-header/95 focus-visible:ring-header",
  };

  return (
    <motion.button
      className={`${baseClass} ${sizeClasses[size]} ${variantClasses[variant]} ${className}`}
      whileHover={{ scale: 1.05, y: -2 }}
      whileTap={{ scale: 0.95, y: 1 }}
      transition={{ type: "spring", stiffness: 300, damping: 15 }}
      {...props}
    >
      {children}
    </motion.button>
  );
};

export default Button;

import React, { useEffect, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import emailjs from "@emailjs/browser";
import { Mail, MapPin, Phone, Send } from "lucide-react";
import send from "../assets/send.png";

const Contact = () => {
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    message: "",
  });
  const [errors, setErrors] = useState({
    fullName: "",
    email: "",
    message: "",
  });

  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const validateField = (e) => {
    let { name, value } = e.target;
    let error = "";
    if (name === "fullName") {
      if (value.trim() === "") {
        error = "Full name is required";
      } else if (value.trim().length < 3) {
        error = "Full name must be at least 3 characters";
      }
    }

    if (name === "email") {
      if (value.trim() === "") {
        error = "Email is required";
      } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
        error = "Invalid email format";
      }
    }
    if (name === "message") {
      if (value.trim() === "") error = "Message is required";
      else if (value.trim().length < 10)
        error = "Message must be at least 10 characters";
    }

    return error;
  };

  const handleChange = (e) => {
    let { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    setErrors((prev) => ({ ...prev, [name]: validateField(e) }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    let newErrors = {};
    Object.keys(formData).forEach((key) => {
      let error = validateField({
        target: { name: key, value: formData[key] },
      });
      if (error) newErrors[key] = error;
    });
    setErrors(newErrors);
    if (Object.values(newErrors).every((err) => err === "")) {
      setIsLoading(true);
      try {
        await emailjs.send(
          "service_3tfvx5g",
          "template_9pkrveg",
          formData,
          "USYbIy1Ege3f42tfg",
        );
        setIsSubmitted(true);
        setIsSuccess(true);
      } catch (error) {
        setIsSubmitted(true);
        setIsSuccess(false);
        console.error("Error sending email:", error.text);
      } finally {
        setIsLoading(false);
      }
    }
  };
  useEffect(() => {
    if (isSubmitted) {
      if (isSuccess) {
        setFormData({ fullName: "", email: "", message: "" });
      }
      const timer = setTimeout(() => {
        setIsSubmitted(false);
      }, 2000);

      return () => clearTimeout(timer);
    }
  }, [isSubmitted, isSuccess]);
  return (
    <section
      id="contact"
      className=" mt-60 flex flex-col items-center relative min-h-screen px-20  z-40 scroll-mt-30"
    >
      <h2 className="text-xl font-semibold mb-6 title-text">
        Get in Touch
      </h2>

      <h3 className="text-3xl md:text-4xl mb-6 font-semibold leading-snug max-w-md">
        Let’s <span className="title-text">work</span> together
      </h3>

      <div className=" flex max-w-4xl w-full flex-col md:flex-row items-start justify-center gap-15">
        <motion.div
          initial={{ opacity: 0, x: -50 }}
          whileInView={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          className="space-y-3 flex-1"
        >
          <p className="text-white/70 text-sm leading-relaxed">
            Have a project, a question, or just want to connect? Feel free to
            reach out.
          </p>

          <p className="text-white/70 text-sm">
            I’m open to new opportunities and ideas.
          </p>

          <div className="mt-6 flex flex-col gap-4 p-5 rounded-xl bg-cyan-800/30 backdrop-blur-sm border border-cyan-700/30">
            <h2 className="text-bold text-lg text-white">
              Contact Information
            </h2>
            <div className="contact-details p-3 flex flex-col gap-8 w-full">
              <div className="flex gap-6 items-center">
                <span className="p-3 bg-cyan-700/20 rounded-xl">
                  <Mail className="contact-icon text-cyan-300 w-5 h-5 " />
                </span>
                <div className="space-y-1">
                  <p className="contact-label text-white/70 text-xs">Email</p>
                  <p className="contact-info text-md text-white">
                    ratnapriya.t@gmail.com
                  </p>
                </div>
              </div>
              <div className="flex gap-6 items-center">
                <span className="p-3 bg-cyan-700/20 rounded-xl">
                  <Phone className="contact-icon text-cyan-300 w-5 h-5 " />
                </span>
                <div className="space-y-1">
                  <p className="contact-label text-white/70 text-xs">Phone</p>
                  <p className="contact-info text-md text-white">
                    +91 9505931088
                  </p>
                </div>
              </div>
              <div className="flex gap-6 items-center">
                <span className="p-3 bg-cyan-700/20 rounded-xl">
                  <MapPin className="contact-icon text-cyan-300 w-5 h-5 " />
                </span>
                <div className="space-y-1">
                  <p className="contact-label text-white/70 text-xs">
                    Location
                  </p>
                  <p className="contact-info text-md text-white">
                    Hyderabad, India
                  </p>
                </div>
              </div>
            </div>
          </div>
        </motion.div>
        <motion.div
          initial={{ opacity: 0, x: 50 }}
          whileInView={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          className="right-section flex-1 w-full min-w-75 max-w-lg h-full z-40"
        >
          <form
            action=""
            className="space-y-5 w-full border border-white/10 p-6 rounded-xl backdrop-blur-sm"
            onSubmit={handleSubmit}
          >
            <div className="flex flex-col">
              <label htmlFor="full-name" className="text-sm mb-6">
                Full Name <span className="">*</span>
              </label>
              <input
                type="text"
                id="full-name"
                className="border-b border-b-white p-2 outline-none focus:border-[#3b6f8e] transition-all duration-300"
                name="fullName"
                value={formData.fullName}
                onChange={handleChange}
              />
              {errors.fullName && (
                <span className="text-red-400 text-sm mt-2">
                  {errors.fullName}
                </span>
              )}
            </div>
            <div className="flex flex-col ">
              <label htmlFor="email" className="text-sm mb-6">
                Email <span>*</span>
              </label>
              <input
                type="email"
                id="email"
                className="border-b border-b-white p-2 outline-none focus:border-[#3b6f8e] transition-all duration-300"
                name="email"
                value={formData.email}
                onChange={handleChange}
              />
              {errors.email && (
                <span className="text-red-400 text-sm mt-2">
                  {errors.email}
                </span>
              )}
            </div>
            <div className="flex flex-col">
              <label htmlFor="message" className="text-sm mb-6">
                Message
              </label>
              <textarea
                id="message"
                rows="5"
                className="border-b border-b-white  relative resize-none z-200  outline-none focus:border-[#3b6f8e] transition-all duration-300"
                name="message"
                value={formData.message}
                onChange={handleChange}
              ></textarea>
              {errors.message && (
                <span className="text-red-400 text-sm mt-2">
                  {errors.message}
                </span>
              )}
            </div>

            <button
              type="submit"
              disabled={isLoading}
              className={`w-full flex items-center justify-center gap-2 px-6 py-3 rounded-full text-sm text-white
  bg-cyan-700/80 border border-cyan-500/40
  shadow-[0_0_15px_rgba(34,211,238,0.25)]
  transition-all duration-300
  hover:bg-cyan-600 hover:shadow-[0_0_25px_rgba(34,211,238,0.35)]
  hover:-translate-y-0.5 active:scale-95
  ${isLoading ? "cursor-not-allowed opacity-80" : ""}`}
            >
              {isLoading ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                  <span>SENDING...</span>
                </>
              ) : (
                <>
                  SEND MESSAGE
                  <Send className="w-4 h-4 group-hover:translate-x-1 transition" />
                </>
              )}
            </button>
          </form>
        </motion.div>
      </div>

      <AnimatePresence>
        {isSubmitted && (
          <motion.div
            initial={{ x: 200, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: 200, opacity: 0 }}
            transition={{ duration: 0.8, ease: "easeInOut" }}
            className={`fixed right-10 top-20 p-5 backdrop-blur-md border border-white z-50 text-sm text-white shadow-[0_0_20px_rgba(56,189,248,0.2)]`}
          >
            {isSuccess ? (
              <>
                Message sent successfully! <br />
                Thank you for reaching out.
              </>
            ) : (
              "Failed to send message. Please try again."
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
};

export default Contact;

import React from "react";
import download from "../assets/download.png";
import arrow from "../assets/arrow.png";
import { motion } from "framer-motion";
import profile from "../assets/profile.jpg";

const Hero = () => {
  const techStack = [
    "HTML",
    "CSS",
    "JavaScript",
    "React",
    "Tailwind CSS",
    "Firebase",
  ];

  const fadeInUp = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" },
    },
  };

  return (
    <section className="pt-20 flex flex-col items-center justify-center relative min-h-screen">
      {/* Content */}
      <div className="relative z-50 flex items-center justify-center gap-8 flex-col md:flex-row px-10 md:px-20">
        {/* LEFT */}
        <motion.div
          className="flex-1"
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.3 }}
          variants={{
            hidden: {},
            visible: {
              transition: {
                staggerChildren: 0.2,
                delayChildren: 0.2,
              },
            },
          }}
        >
          <motion.h1
            className="text-3xl md:text-4xl leading-tight"
            variants={fadeInUp}
          >
            Crafting{" "}
            <span className="title-text">
              modern
            </span>{" "}
            web experiences with{" "}
            <span className="italic text-white/90 tracking-wider font-bodoni">
              precision
            </span>
          </motion.h1>

          <motion.p
            className="mt-4 text-sm text-white/70 max-w-md"
            variants={fadeInUp}
          >
            Hi, I am Ratna Priya — a frontend developer with a background in
            banking, now focused on building modern, responsive web applications
            that are clean, intuitive, and user-focused.
          </motion.p>

          {/* CTA */}
          <motion.div
            className="flex flex-col lg:flex-row items-stretch lg:items-center gap-4 lg:gap-8 mt-10 w-full lg:w-auto"
            variants={fadeInUp}
          >
            {/* Get in Touch */}
            <a
              href="#contact"
              className="w-full md:w-auto justify-center
              px-6 py-3 rounded-full flex items-center gap-2 text-sm text-white
              bg-cyan-700/80 border border-cyan-500/40
              shadow-[0_0_15px_rgba(34,211,238,0.25)]
              transition-all duration-300
              hover:bg-cyan-600
              hover:shadow-[0_0_25px_rgba(34,211,238,0.35)]
              hover:-translate-y-0.5
              active:scale-95"
            >
              Get In Touch
              <img src={arrow} alt="arrow" className="w-4" />
            </a>

            {/* Download Resume */}
            <div className="relative inline-block w-full md:w-auto rounded-full p-px">
              <div className="absolute inset-0 rounded-full animate-border-move z-0"></div>

              <a
                href="/resume.pdf"
                download
                className="w-full md:w-auto justify-center
                relative z-10 px-5 py-3 text-sm md:text-xs
                bg-black text-white rounded-full flex items-center gap-2
                active:scale-95 transition-transform duration-200
                shadow-lg shadow-header/25
                focus-visible:ring-2 focus-visible:ring-header/50"
              >
                <img src={download} alt="Download Resume" className="w-5" />
                Download Resume
              </a>
            </div>
          </motion.div>
        </motion.div>

        {/* RIGHT */}
        <div className="flex-1 ">
          <div className="img w-3/4 md:w-80 h-80 mx-auto rounded-2xl overflow-hidden border-2 border-cyan-500/30 shadow-[0_0_20px_rgba(34,211,238,0.45)]">
            <img src={profile} alt="Profile" />
          </div>
        </div>
      </div>

      {/* Tech Stack */}
      <motion.div
        className="mt-16 md:mt-20 z-40"
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true }}
        variants={{
          hidden: {},
          visible: {
            transition: { staggerChildren: 0.1 },
          },
        }}
      >
        <h3 className="text-sm px-4 py-2 bg-black/60 border border-cyan-500/20 rounded-full text-white mb-6 text-center shadow-[0_0_20px_rgba(34,211,238,0.1)]">
          Technologies I work with
        </h3>

        <div className="flex flex-wrap gap-4 justify-center">
          {techStack.map((tech, index) => (
            <motion.span
              key={index}
              variants={fadeInUp}
              className="bg-black/50 text-cyan-300 px-3 py-1 rounded-full text-sm
              shadow-md shadow-header/25 transition-all duration-300
              hover:-translate-y-1 hover:shadow-[0_0_15px_rgba(34,211,238,0.25)]"
            >
              {tech}
            </motion.span>
          ))}
        </div>
      </motion.div>
    </section>
  );
};

export default Hero;
